import{c as d,Q as o,j as t,m as a}from"./chunks/framework.ByJJFMw8.js";const m=JSON.parse('{"title":"Supported Formats","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/formats.md","filePath":"en/guide/formats.md","lastUpdated":1782194586000}'),r={name:"en/guide/formats.md"};function c(i,e,n,s,l,p){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="supported-formats" tabindex="-1">Supported Formats <a class="header-anchor" href="#supported-formats" aria-label="Permalink to &quot;Supported Formats&quot;">​</a></h1><div class="doc-kicker">Format Truth</div><p class="doc-lead"> The current core declares 24 preview pipelines and 206 file extensions. Renderers are loaded on demand, so opening a lightweight text file does not force the browser to load every heavy document engine. </p><h2 id="main-preview-pipelines" tabindex="-1">Main Preview Pipelines <a class="header-anchor" href="#main-preview-pipelines" aria-label="Permalink to &quot;Main Preview Pipelines&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Examples</th></tr></thead><tbody><tr><td>Word</td><td><code>docx</code>, <code>docm</code>, <code>dotx</code>, <code>dotm</code>, legacy <code>doc</code>, <code>dot</code>, plus RTF and ODT paths</td></tr><tr><td>Spreadsheets</td><td><code>xlsx</code>, <code>xlsm</code>, <code>xlsb</code>, <code>xls</code>, <code>csv</code>, <code>ods</code>, <code>fods</code>, <code>numbers</code></td></tr><tr><td>Presentations</td><td><code>pptx</code>, <code>pptm</code>, <code>potx</code>, <code>potm</code>, <code>ppsx</code>, <code>ppsm</code>, <code>odp</code></td></tr><tr><td>Layout documents</td><td><code>pdf</code>, <code>ofd</code>, <code>typ</code>, <code>typst</code></td></tr><tr><td>Archives</td><td><code>zip</code>, <code>7z</code>, <code>rar</code>, <code>tar</code>, <code>gz</code>, <code>tgz</code>, <code>cab</code>, <code>iso</code>, <code>apk</code>, <code>cbz</code>, <code>cbr</code>, and more</td></tr><tr><td>Email</td><td><code>eml</code>, <code>msg</code>, <code>mbox</code></td></tr><tr><td>Diagrams and mind maps</td><td><code>xmind</code>, <code>drawio</code>, <code>dio</code>, <code>excalidraw</code>, <code>mermaid</code>, <code>mmd</code>, <code>plantuml</code>, <code>puml</code></td></tr><tr><td>CAD and engineering</td><td><code>dwg</code>, <code>dxf</code>, <code>dwf</code>, <code>dwfx</code>, <code>xps</code>, plus EDA files such as <code>gds</code>, <code>oas</code>, <code>oasis</code>, <code>olb</code>, <code>dra</code></td></tr><tr><td>3D and geospatial</td><td><code>gltf</code>, <code>glb</code>, <code>obj</code>, <code>stl</code>, <code>ply</code>, <code>step</code>, <code>stp</code>, <code>iges</code>, <code>ifc</code>, <code>3dm</code>, <code>brep</code>, <code>geojson</code>, <code>kml</code>, <code>gpx</code>, <code>shp</code></td></tr><tr><td>Text, code, and data</td><td>Markdown, source code, logs, JSON, YAML, TOML, SQL, IPYNB, SQLite, WASM, Parquet, Avro</td></tr><tr><td>Media and assets</td><td>Images, SVG, HEIC, audio, video, HLS, fonts, PSD-style design assets</td></tr></tbody></table><h2 id="engineering-renderer-notes" tabindex="-1">Engineering Renderer Notes <a class="header-anchor" href="#engineering-renderer-notes" aria-label="Permalink to &quot;Engineering Renderer Notes&quot;">​</a></h2><ul><li>Word preview uses <code>@file-viewer/renderer-word</code>. The package lazy-loads the self-maintained DOCX engine, <code>msdoc-viewer</code>, and RTF/OpenDocument helpers only for DOCX/DOC/RTF/ODT files, so core-only and lightweight component installs do not pull Word engines by default.</li><li>XMind uses <code>@file-viewer/renderer-mindmap</code> with XMind 8 XML and XMind 2020+ JSON package parsing, plus an <code>@panzoom/panzoom</code> powered canvas for drag panning, node-start dragging, mobile pinch zoom, keyboard panning, responsive fit-on-open/host-resize behavior, and unified toolbar state sync after pan/navigation.</li><li>Mermaid and PlantUML are handled by <code>@file-viewer/renderer-drawing</code>. Mermaid lazy-loads the official <code>mermaid</code> renderer and outputs theme-aware SVG. PlantUML stays offline by default with an SVG source preview; configure <code>options.drawing.plantumlServerUrl</code> when an intranet PlantUML SVG service is available. If the endpoint is unavailable, the viewer renders the same offline preview instead of leaving the page blank. Both diagram surfaces support drag panning and renderer-native zoom controls through <code>@panzoom/panzoom</code>.</li><li>Patch files are rendered with <code>diff2html</code> in side-by-side mode. Git bundles parse the bundle header, refs, commit objects, trees, readable blobs, and regular OFS_DELTA / REF_DELTA pack objects directly in the browser; very large packs or bundles that depend on external prerequisites surface a clear boundary notice instead of being silently misrepresented.</li><li>EDA uses <code>@file-viewer/renderer-eda</code>. OLB and DRA are safe structure previews over common CFB/OLE2 containers, standard GDSII renders small layouts as SVG and larger element sets through WebGL typed-array batches, readable OASIS text fixtures render as SVG, and real SEMI binary OASIS remains a safe structure-index preview until the dedicated WASM/WebGL layout kernel is split out.</li><li>CAD uses <code>@file-viewer/renderer-cad</code> and <code>@flyfish-dev/cad-viewer</code>; DWG, DWF, and DWFx assets remain self-hostable for offline deployments.</li><li>STEP, IGES, IFC, 3DM, and BREP use the <code>@file-viewer/renderer-3d</code> entry plus the lightweight <code>@file-viewer/geometry-engine</code> route package for signature detection and accurate conversion guidance. Full visual decoding still belongs in dedicated OpenCascade / web-ifc / rhino3dm WASM paths, not in core or default component installs.</li></ul><h2 id="capability-model" tabindex="-1">Capability Model <a class="header-anchor" href="#capability-model" aria-label="Permalink to &quot;Capability Model&quot;">​</a></h2><p>Each renderer reports what it can safely do. The common toolbar then shows download, print, HTML export, zoom, search, and navigation only when the active file type supports those operations.</p><p>This avoids pretending that every format supports the same operations. Word and PDF can use full-page print adapters, images can zoom naturally, archives can lazy-extract nested entries, and virtual spreadsheet tables are provided by <code>@file-viewer/renderer-spreadsheet</code> to avoid fragile outer CSS scaling.</p><h2 id="best-evaluation-path" tabindex="-1">Best Evaluation Path <a class="header-anchor" href="#best-evaluation-path" aria-label="Permalink to &quot;Best Evaluation Path&quot;">​</a></h2><ol><li>Open the <a href="https://demo.file-viewer.app" target="_blank" rel="noreferrer">live demo</a>.</li><li>Try the sample closest to your production files.</li><li>Test your own file through upload or URL.</li><li>Use the <a href="https://demo.file-viewer.app/compare.html" target="_blank" rel="noreferrer">comparison demo</a> for contract, report, and generated-output review.</li><li>If your deployment is offline or CSP-restricted, run <code>npx file-viewer-copy-assets ./public/file-viewer</code> and point renderer assets to your own static path.</li></ol>',12)])])}const u=d(r,[["render",c]]);export{m as __pageData,u as default};
